141	enum common_chat_tool_choice {
142	    COMMON_CHAT_TOOL_CHOICE_AUTO,
143	    COMMON_CHAT_TOOL_CHOICE_REQUIRED,
144	    COMMON_CHAT_TOOL_CHOICE_NONE,
145	};
146	
147	enum common_chat_format {
148	    COMMON_CHAT_FORMAT_CONTENT_ONLY,
149	
150	    // These are intended to be parsed by the PEG parser
151	    COMMON_CHAT_FORMAT_PEG_SIMPLE,
152	    COMMON_CHAT_FORMAT_PEG_NATIVE,
153	    COMMON_CHAT_FORMAT_PEG_GEMMA4,
154	
155	    COMMON_CHAT_FORMAT_COUNT,  // Not a format, just the # formats
156	};
157	
158	struct common_chat_templates_inputs {
159	    std::vector<common_chat_msg>          messages;
160	    std::string                           grammar;
161	    std::string                           json_schema;
162	    bool                                  add_generation_prompt = true;
163	    bool                                  use_jinja             = true;
164	    // Parameters below only supported when use_jinja is true
165	    std::vector<common_chat_tool>         tools;
166	    common_chat_tool_choice               tool_choice         = COMMON_CHAT_TOOL_CHOICE_AUTO;
167	    bool                                  parallel_tool_calls = false;
168	    common_reasoning_format               reasoning_format    = COMMON_REASONING_FORMAT_NONE; // TODO: refactor this to "bool enable_thinking"
169	    bool                                  enable_thinking     = true;
170	    std::chrono::system_clock::time_point now                 = std::chrono::system_clock::now();
171	    std::map<std::string, std::string>    chat_template_kwargs;
172	    bool                                  add_bos = false;
173	    bool                                  add_eos = false;
174	    bool                                  force_pure_content = false;
175	};
176	
177	struct common_chat_params {
178	    common_chat_format                  format = COMMON_CHAT_FORMAT_CONTENT_ONLY;
179	    std::string                         prompt;
180	    std::string                         grammar;
181	    bool                                grammar_lazy         = false;
182	    std::string                         generation_prompt;
183	    bool                                supports_thinking    = false;
184	    std::string                         thinking_start_tag;  // e.g., "<think>"
185	    std::string                         thinking_end_tag;    // e.g., "</think>"
186	    std::vector<common_grammar_trigger> grammar_triggers;
187	    std::vector<std::string>            preserved_tokens;
188	    std::vector<std::string>            additional_stops;
189	    std::string                         parser;
190	};
191	
192	// per-message parsing syntax
193	// should be derived from common_chat_params
194	struct common_chat_parser_params {
195	    common_chat_format      format               = COMMON_CHAT_FORMAT_CONTENT_ONLY;
196	    common_reasoning_format reasoning_format     = COMMON_REASONING_FORMAT_NONE; // TODO: refactor this to "bool parse_reasoning"
197	    // Whether reasoning_content should be inlined in the content (e.g. for reasoning_format=deepseek in stream mode)
198	    bool                    reasoning_in_content = false;
199	    std::string             generation_prompt;
200	    bool                    parse_tool_calls     = true;
201	    bool                    debug                = false;  // Enable debug output for PEG parser
202	    common_peg_arena        parser               = {};
203	    common_chat_parser_params() = default;
204	    common_chat_parser_params(const common_chat_params & chat_params) {
205	        format  = chat_params.format;
206	        generation_prompt = chat_params.generation_prompt;
207	    }
208	};
